{"code": "import os
import json

# Check what files are in the /tmp directory
tmp_files = os.listdir('/tmp')
print('Files in /tmp:')
for f in sorted(tmp_files):
    print('  ' + f)

# Check local variables
print('\nChecking local variables for query results...')
all_vars = list(locals().keys())
query_vars = [v for v in all_vars if str(v).startswith('var_')]
print('Found variables: ' + str(query_vars))

# Try to access each variable
for var_name in query_vars:
    print('\nVariable: ' + var_name)
    try:
        data = locals()[var_name]
        print('  Type: ' + str(type(data)))
        if isinstance(data, list):
            print('  Length: ' + str(len(data)))
            if len(data) > 0:
                print('  Sample item: ' + str(data[0]))
        elif isinstance(data, str):
            print('  String value: ' + data)
            if '.json' in data and os.path.exists(data):
                with open(data, 'r') as f:
                    file_data = json.load(f)
                    print('  File contains: ' + str(type(file_data)) + ' of length ' + str(len(file_data)))
    except Exception as e:
        print('  Error: ' + str(e))"}

